-- Turkish Police Job - Server Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal PoliceData = {}\nlocal Arrests = {}\n\nRegisterNetEvent('police:server:goOnDuty')\nAddEventHandler('police:server:goOnDuty', function()\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    if Player.PlayerData.job.name ~= 'police' then\n        TriggerClientEvent('QBCore:Notify', src, 'Polis degilsin!', 'error')\n        return\n    end\n    \n    PoliceData[src] = {onDuty = true, arrests = 0, fines = 0, startTime = os.time()}\n    TriggerClientEvent('QBCore:Notify', src, 'Gorevde oldunuz!', 'success')\nend)\n\nRegisterNetEvent('police:server:arrest')\nAddEventHandler('police:server:arrest', function(targetId, reason, bail)\n    local src = source\n    local Arrester = QBCore.Functions.GetPlayer(src)\n    local Arrestee = QBCore.Functions.GetPlayer(targetId)\n    if not Arrester or not Arrestee then return end\n    if Arrester.PlayerData.job.name ~= 'police' then return end\n    \n    Arrests[targetId] = {\n        arrestedBy = Arrester.PlayerData.charinfo.firstname,\n        reason = reason,\n        bail = bail,\n        arrestTime = os.time()\n    }\n    \n    TriggerClientEvent('QBCore:Notify', src, 'Oyuncu tutukland!', 'success')\n    TriggerClientEvent('QBCore:Notify', targetId, 'Tutuklandınız! Tutuksuz bırakılma: $' .. bail, 'error')\nend)\n\nprint('^2[Turkish Police Job] Yuklendi!^7')"